solution_code:
#include <iostream>
#include <string>
#include <vector>

class Player
{
    std::string m_name;

public:
    Player(const std::string& name) : m_name{ name } {}
    const std::string& getName() const { return m_name; }
};

class Team
{
    std::vector<const Player*> m_players{};

public:
    void addPlayer(const Player& p) { m_players.push_back(&p); }
    void printRoster(std::ostream& out) const
    {
        out << "Team roster:" << '\n';
        for (const Player* p : m_players)
            out << "- " << p->getName() << '\n';
    }
};

int main()
{
    int n{};
    std::cin >> n;

    std::vector<Player> players{};
    players.reserve(static_cast<std::size_t>(n));
    for (int i{ 0 }; i < n; ++i)
    {
        std::string name{};
        std::cin >> name;
        players.push_back(Player{ name });
    }

    {
        Team team{};
        for (const Player& p : players)
            team.addPlayer(p);
        team.printRoster(std::cout);
    }

    std::cout << "Players still exist" << '\n';

    return 0;
}
